def validate(args, output):
    n = args[0]
    if not isinstance(output, list):
        return False
    total = n * (n - 1)
    if n <= 4:
        return output == []
    if len(output) != total:
        return False
    seen = set()
    for m in output:
        if not isinstance(m, list) or len(m) != 2:
            return False
        a, b = m[0], m[1]
        if not (0 <= a < n and 0 <= b < n) or a == b:
            return False
        if (a, b) in seen:
            return False
        seen.add((a, b))
    if len(seen) != total:
        return False
    for i in range(1, len(output)):
        if set(output[i]) & set(output[i - 1]):
            return False
    return True

