function validate(args, output) {
    const n = args[0];
    if (!Array.isArray(output)) return false;
    const total = n * (n - 1);
    if (n <= 4) return output.length === 0;
    if (output.length !== total) return false;
    const seen = new Set();
    for (const m of output) {
        if (!Array.isArray(m) || m.length !== 2) return false;
        const a = m[0], b = m[1];
        if (!(a >= 0 && a < n && b >= 0 && b < n) || a === b) return false;
        const key = a * n + b;
        if (seen.has(key)) return false;
        seen.add(key);
    }
    if (seen.size !== total) return false;
    for (let i = 1; i < output.length; i++) {
        const prev = new Set(output[i - 1]);
        if (prev.has(output[i][0]) || prev.has(output[i][1])) return false;
    }
    return true;
}

