class Solution:
    def generateSchedule(self, n):
        if n <= 4:
            return []
        rem = [[a != b for b in range(n)] for a in range(n)]
        total = n * (n - 1)
        deg = [2 * (n - 1) for _ in range(n)]
        seq = []
        forbidden = set()
        for _ in range(total):
            best = None
            best_key = None
            for a in range(n):
                if a in forbidden or deg[a] == 0:
                    continue
                for b in range(n):
                    if a == b or b in forbidden or not rem[a][b]:
                        continue
                    key = (deg[a] + deg[b], deg[a] * deg[b])
                    if best_key is None or key > best_key:
                        best_key = key
                        best = (a, b)
            if best is None:
                return []
            a, b = best
            rem[a][b] = False
            deg[a] -= 1
            deg[b] -= 1
            seq.append([a, b])
            forbidden = {a, b}
        return seq

