solutions.javascript:
var generateSchedule = function(n) {
    if (n <= 4) return [];
    const rem = Array.from({length: n}, (_, a) => Array.from({length: n}, (_, b) => a !== b));
    const total = n * (n - 1);
    const deg = new Array(n).fill(2 * (n - 1));
    const seq = [];
    let forbidden = new Set();
    for (let step = 0; step < total; step++) {
        let bestA = -1, bestB = -1, bestSum = -1, bestProd = -1;
        for (let a = 0; a < n; a++) {
            if (forbidden.has(a) || deg[a] === 0) continue;
            for (let b = 0; b < n; b++) {
                if (a === b || forbidden.has(b) || !rem[a][b]) continue;
                const sum = deg[a] + deg[b], prod = deg[a] * deg[b];
                if (sum > bestSum || (sum === bestSum && prod > bestProd)) {
                    bestSum = sum; bestProd = prod; bestA = a; bestB = b;
                }
            }
        }
        if (bestA === -1) return [];
        rem[bestA][bestB] = false; deg[bestA]--; deg[bestB]--;
        seq.push([bestA, bestB]); forbidden = new Set([bestA, bestB]);
    }
    return seq;
};
